package br.gov.siscomex.portalunico.plat.api;

import br.gov.siscomex.portalunico.plat.model.AuthResponseDTO;
import br.gov.siscomex.portalunico.plat.model.ErrorResponseDTO;
import io.swagger.annotations.Api;
import io.swagger.annotations.ApiOperation;
import io.swagger.annotations.ApiParam;
import io.swagger.annotations.ApiResponse;
import io.swagger.annotations.ApiResponses;

import javax.ws.rs.HeaderParam;
import javax.ws.rs.POST;
import javax.ws.rs.Path;
import javax.ws.rs.Produces;

/**
 * Autenticação
 *
 * <p><style>.first-col{width:200px;}</style><p>Os serviços de autenticação são responsávels por validar a identidade do usuário e verificar se este possui autorização para atuar no perfil informado.</p><p>Na versão atual, o portal disponibiliza os seguintes tipos de autenticação:</p><ol><li>Autenticação por certificado digital (mTLS)</li><li>Autenticação com par de chaves de acesso</li></ol><h2>Autenticação por certificado digital (mTLS)</h2><p>Esse tipo de autenticação implementa o protocolo <i>mTLS</i> (Mutual Transport Layer Security) o qual garante que tanto o cliente quanto o servidor se autentiquem mutuamente antes de estabelecer uma conexão. Ao acionar o serviço de autenticação, será preciso realizar o processo de handshake SSL entre a aplicação cliente e o portal, apresentando um certificado digital válido e reconhecido pelo SERPRO. Os serviços de autenticação de usuários aceitam certificados de pessoa física (e-CPF) ou jurídica (e-CNPJ) nos formatos A1 e A3 emitidos por autoridade certificadora no padrão ICP Brasil. A autenticação de sistemas com certificado de equipamento (SSL) é de uso exclusivo dos órgãos da administração pública.</p><p>As plataformas de desenvolvimento atuais já implementam o fluxo de Handshake mTLS. Em geral, basta configurar algumas variáveis de ambiente e a API se encarrega de executar o protocolo. Em resumo, o processo acontece da seguinte forma:</p><ol><li>O cliente inicia o pedido de conexão com o serviço; </li><li>O serviço retorna o seu certificado assinado para que seja verificado pelo cliente; </li><li>O cliente verifica a sequência de cadeias de autoridades certificadoras presentes no certificado e compara com as cadeias presentes na TrustStore local; </li><li>O cliente envia o seu certificado encapsulado em uma Keystore para que seja reconhecido pelo servidor; </li><li>O servidor valida o certificado do cliente; </li><li>O processo de handshake é finalizado e o cliente pode realizar a requisição ao serviço.</li></ol></br><img alt=\"Fluxo de autenticação mTLS\" src=\"data:image/png;base64,\"></br><h2>Autenticação por chaves de acesso</h2><p>Nessa alternativa, um usuário que habilitado para login via tela, consegue gerar um par de chaves para autenticação e acesso via API de serviços. Com isso, não será mais necessário o compartilhamento do certificado A1 para serem embarcados em sistemas de terceiros. O detentor do par de chaves conseguirá se autenticar e acionar os serviços com a identidade do usuário proprietário da chave.</p><p>O par de chaves é passado por meio de headers na chamada de autenticação sem a necessidade de certificados digitais</p><p>As instruções para geração e manutenção de chaves de acesso estão descritas em uma seção específica acessível no menu à esquerda.</p></br><h2>Perfis de Acesso (Role-Type)</h2><p>Na seguinte tabela estão listados os valores possíveis para o cabeçalho \"Role-Type\" indicando o perfil de atuação do usuário. Para cada perfil, a tabela também informa se a autenticação admite certificado digital de pessoa física (e-CPF), de pessoa jurídia (e-CNPJ) ou ambos.</p></br><table> <thead> <tr> <th style=\"text-align: left;\">Nome</th> <th style=\"text-align: left;\">Descrição</th> <th style=\"text-align: center;\">e-CPF</th> <th style=\"text-align: center;\">e-CNPJ</th> </tr> </thead> <tbody> <tr> <td style=\"text-align: left;\">IMPEXP</td> <td style=\"text-align: left;\">Declarante importador/exportador</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">DEPOSIT</td> <td style=\"text-align: left;\">Depositário</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\">X</td> </tr> <tr> <td style=\"text-align: left;\">OPERPORT</td> <td style=\"text-align: left;\">Operador Portuário</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\">X</td> </tr> <tr> <td style=\"text-align: left;\">TRANSPORT</td> <td style=\"text-align: left;\">Transportador</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\">X</td> </tr> <tr> <td style=\"text-align: left;\">TRANSPEST</td> <td style=\"text-align: left;\">PF – Representante de TETI</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">AGECARGA</td> <td style=\"text-align: left;\">Agente de Carga</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">AGEREMESS</td> <td style=\"text-align: left;\">Remessa Expressa/Correio</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\">X</td> </tr> <tr> <td style=\"text-align: left;\">AJUDESPAC</td> <td style=\"text-align: left;\">Ajudante de Despachante</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">INSTFINANC</td> <td style=\"text-align: left;\">Instituição Financeira</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">CONTATOOEA</td> <td style=\"text-align: left;\">Ponto de Contato OEA</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">RESPLEGAL</td> <td style=\"text-align: left;\">Responsável Legal OE</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">HABILITAD</td> <td style=\"text-align: left;\">Habilitador</td> <td style=\"text-align: center;\">X</td> <td style=\"text-align: center;\"></td> </tr> <tr> <td style=\"text-align: left;\">TERCEIROS</td> <td style=\"text-align: left;\">Terceiros (Outros Intervenientes)</td> <td style=\"text-align: center;\"></td> <td style=\"text-align: center;\">X</td> </tr> </tbody> </table></br><h2>Resposta de autenticação</h2><p>Se a autenticação for bem sucedida, os seguintes <i>response headers</i> serão retornados:</p></br><table> <thead> <tr> <th><span>Nome</span></th> <th>Descrição</th> <th>Tipo</th> </tr> </thead> <tbody> <tr> <td>Set-Token</td> <td>JSON Web Token (JWT) contendo as informações do usuário. Conforme o padrão JWT, esse token poderá ser decodificado (Base64) a fim de se extrair as informações do usuário para que as mesmas sejam utilizadas na aplicação cliente. O token é assinado digitalmente pelo servidor e verificado a cada requisição, garantindo a sua inviolabilidade.</td> <td>string</td> </tr> <tr> <td>X-CSRF-Token</td> <td>Token de prevenção contra ataques CSRF (Cross-Site Request Forgery). Ao contrário do JWT, esse token é criptografado e pode ser decodificado apenas no servidor. O token possui um tempo de vida de 60 minutos. A cada nova requisição, para qualquer endpoint do Portal, o token é gerado novamente pelo servidor e devolvido no header do response com o tempo de expiração renovado. Dessa forma, a cada nova requisição, dentro do prazo de 60 minutos, utilize o token renovado que foi recebido na requisição anterior, sem precisar chamar novamente o endpoint de autenticação.</td> <td>string</td> </tr> <tr> <td>X-CSRF-Expiration</td> <td>Data de expiração do X-CSRF-Token, em milisegundos. Após essa data, o token não será mais aceito no servidor.</td> <td>string</td> </tr> </tbody> </table></br><h2>Códigos de erro</h2><p>Os erros listados na tabela abaixo indicam cenários de problemas a serem resolvidos do lado do sistema chamador. </p></br><table><thead><tr><th class=\"first-col\">Código</th><th>Mensagem</th><th>Observações</th></tr></thead><tbody><tr><td>PUCX-ER0101</td><td>O cabeçalho 'Role-Type' não está na requisição</td><td></td></tr><tr><td>PUCX-ER0102</td><td>O cabeçalho 'Role-Type' é inválido.</td><td>Verifique a lista de domínio na tabela <b>Perfis de Acesso</b></td></tr><tr><td>PUCX-ER0401</td><td>O Portal Único de Comércio Exterior encontra-se em uma parada programada que ocorre diariamente entre 01:00 e 03:00</td><td>A API fica indisponível durante esse período.</td></tr><tr><td>PLAT-ER2001</td><td>Não foi possível identificar um certificado digital válido.</td><td>O handshake da autenticação mTLS não foi efetuada com sucesso.</td></tr><tr><td>PLAT-ER2008</td><td>A autenticação com e-CNPJ não é válida para o perfil selecionado. Para esse perfil deve ser utilizado um certificado do tipo e-CPF.</td><td>Verifique a sinalização na tabela <b>Perfis de Acesso</b> </td></tr><tr><td>PLAT-ER2013</td><td>Usuário não possui representações no perfil selecionado.</td><td><a href=\"https://www.gov.br/receitafederal/pt-br/assuntos/aduana-e-comercio-exterior/manuais/subportais-aduana-e-comercio-exterior/intervenientes/habilitacao-em-sistemas-aduaneiros\" target=\"_blank\">Informações sobre acesso a sistemas aduaneiros</a></td></tr><tr><td>PLAT-ER2023</td><td>O CNPJ não possui habilitação para atuar no perfil selecionado.</td><td><a href=\"https://www.gov.br/receitafederal/pt-br/assuntos/aduana-e-comercio-exterior/manuais/subportais-aduana-e-comercio-exterior/intervenientes/habilitacao-em-sistemas-aduaneiros\" target=\"_blank\">Informações sobre acesso a sistemas aduaneiros</a></td></tr><tr><td>PLAT-ER2033</td><td>Operação não autorizada. Usuário realizou autenticação válida nos últimos 60 segundos.</td><td>Mecanismo para bloqueio de acesso massivo. Verifique a orientação na descrição do atributo <b>X-CSRF-Token</b> </td></tr><tr><td>PLAT-ER3005</td><td>O CPF do usuário não está em situação regular.</td><td>Verifique o motivo descrito na mensagem.</td></tr><tr><td>PLAT-ER8001</td><td>Não foi possível identificar um certificado digital de equipamento válido.</td><td>Serviço de autenticação para órgãos públicos com certificados de equipamento (SSL).</td></tr><tr><td>PLAT-ER8002</td><td>O certificado digital não está habilitado no Portal Único do Comércio Exterior.</td><td>A habilitação do certificado do órgão público deve ser solicitada à SECEX.</td></tr><tr><td>PLAT-ER8003</td><td>A chave de acesso enviada não é válida.</td><td>O <b>System-Code</b> enviado é inválido ou inexistente.</td></tr><tr><td>PLAT-ER8004</td><td>O cadastro de sistema integrado não está mais ativo.</td><td>A habilitação do sistema foi desativada pela SECEX.</td></tr><tr><td>PLAT-ER8008</td><td>Não foi possível efetuar a autenticação com chave de acesso.</td><td>Verifique o motivo descrito na mensagem.</td></tr></tbody></table></br><h3>Erros não mapeados</h3><p>Se algum outro erro acontecer, siga a orientação retornada na mensagem. Se necessário, acione a Central de Serviços Serpro anexando o conteúdo do response de erro recebido.</p></br><h2>Ambientes e URLs de Acesso</h2>A documentação sobre ambientes está disponível na seção <a href=\"../../ambiente\">Aspectos Gerais > Ambientes</a></br></br><b>URL Base:</b>{ambiente}/portal/
 *
 */
@Path("/")
@Api(value = "/", description = "")
public interface ServicosDeAutenticacaoApi {

    /**
     * Autentica o usuário a partir do par de chaves de acesso gerado no portal
     * <p>
     * Efetua a autenticação básica do par de chaves. O par de chaves deve ser fornecido pelo usuário que deseja compartilhar sua credencial.
     *
     */
    @POST
    @Path("/api/autenticar/chave-acesso")
    @Produces({"application/json", "*/*"})
    @ApiOperation(value = "Autentica o usuário a partir do par de chaves de acesso gerado no portal", notes = "Efetua a autenticação básica do par de chaves. O par de chaves deve ser fornecido pelo usuário que deseja compartilhar sua credencial.", tags = {"Servicos de autenticacao"})
    @ApiResponses(value = {
            @ApiResponse(code = 200, message = "Operação realizada com sucesso", response = AuthResponseDTO.class),
            @ApiResponse(code = 422, message = "Erro(s) de validação da camada de negócio", response = ErrorResponseDTO.class),
            @ApiResponse(code = 500, message = "Erro interno no servidor", response = ErrorResponseDTO.class)})
    AuthResponseDTO autenticarChaveAcesso(@ApiParam(value = "Chave de identificação do usuário", required = true) @HeaderParam("Client-Id") String clientId, @ApiParam(value = "Chave secreta", required = true) @HeaderParam("Client-Secret") String clientSecret, @ApiParam(value = "Perfil de atuação do usuário", required = true) @HeaderParam("Role-Type") String roleType);

    /**
     * Autentica o sistema a partir do par de chaves de acesso gerado no portal
     * <p>
     * Efetua a autenticação básica do par de chaves. O par de chaves deve ser fornecido por algum usuário cadastrado como responsável pelo sistema integrado. Esse tipo de autenticação é de uso restrito dos órgãos da administração pública.
     *
     */
    @POST
    @Path("/api/autenticar/chave-acesso/sistema")
    @Produces({"application/json", "*/*"})
    @ApiOperation(value = "Autentica o sistema a partir do par de chaves de acesso gerado no portal", notes = "Efetua a autenticação básica do par de chaves. O par de chaves deve ser fornecido por algum usuário cadastrado como responsável pelo sistema integrado. Esse tipo de autenticação é de uso restrito dos órgãos da administração pública.", tags = {"Servicos de autenticacao"})
    @ApiResponses(value = {
            @ApiResponse(code = 200, message = "Operação realizada com sucesso", response = AuthResponseDTO.class),
            @ApiResponse(code = 422, message = "Erro(s) de validação da camada de negócio", response = ErrorResponseDTO.class),
            @ApiResponse(code = 500, message = "Erro interno no servidor", response = ErrorResponseDTO.class)})
    AuthResponseDTO autenticarChaveAcessoSistema(@ApiParam(value = "Chave de identificação do usuário", required = true) @HeaderParam("Client-Id") String clientId, @ApiParam(value = "Chave secreta", required = true) @HeaderParam("Client-Secret") String clientSecret, @ApiParam(value = "Chave de identificação do sistema integrado", required = true) @HeaderParam("System-Code") String systemCode);

    /**
     * Autentica o sistema a partir do certificado digital de equipamento previamente habilitado
     * <p>
     * Efetua a autenticação mútua (mTLS) do certificado digital de equipamento (SSL). O certificado deve ser previamente habilitado por um usuário cadastrador de sistemas integrados do portal. Esse tipo de autenticação é de uso restrito dos órgãos da administração pública.
     *
     */
    @POST
    @Path("/api/autenticar/sistema")
    @Produces({"application/json"})
    @ApiOperation(value = "Autentica o sistema a partir do certificado digital de equipamento previamente habilitado", notes = "Efetua a autenticação mútua (mTLS) do certificado digital de equipamento (SSL). O certificado deve ser previamente habilitado por um usuário cadastrador de sistemas integrados do portal. Esse tipo de autenticação é de uso restrito dos órgãos da administração pública.", tags = {"Servicos de autenticacao"})
    @ApiResponses(value = {
            @ApiResponse(code = 200, message = "Operação realizada com sucesso", response = AuthResponseDTO.class),
            @ApiResponse(code = 422, message = "Erro(s) de validação da camada de negócio"),
            @ApiResponse(code = 500, message = "Erro interno no servidor")})
    AuthResponseDTO autenticarSistema(@ApiParam(value = "Chave que identifica o sistema integrado associado à um órgão da administração pública", required = true) @HeaderParam("System-Code") String systemCode);

    /**
     * Autentica o usuário a partir do certificado digital de pessoa física ou jurídica
     * <p>
     * Efetua a autenticação mútua (mTLS) do certificado digital e-CPF ou e-CNPJ padrão ICP Brasil.
     *
     */
    @POST
    @Path("/api/autenticar")
    @Produces({"application/json"})
    @ApiOperation(value = "Autentica o usuário a partir do certificado digital de pessoa física ou jurídica", notes = "Efetua a autenticação mútua (mTLS) do certificado digital e-CPF ou e-CNPJ padrão ICP Brasil.", tags = {"Servicos de autenticacao"})
    @ApiResponses(value = {
            @ApiResponse(code = 200, message = "Operação realizada com sucesso", response = AuthResponseDTO.class),
            @ApiResponse(code = 422, message = "Erro(s) de validação da camada de negócio"),
            @ApiResponse(code = 500, message = "Erro interno no servidor")})
    AuthResponseDTO autenticarUsuario(@ApiParam(value = "Perfil de atuação do usuário. A lista de perfis está descrita na tabela de **Perfis de Acesso** na seção acima.", required = true) @HeaderParam("Role-Type") String roleType);
}

